{
  "summary": "This paper proposes embedding-based Mahalanobis distance scores and a binary classifier approach for out-of-distribution (OOD) detection in conditional language models (CLMs), combined with perplexity to enable selective generation of high-quality outputs. Evaluated on summarization and translation tasks, the methods outperform perplexity and other baselines in OOD detection and improve correlation with quality metrics for selective generation.",
  "strengths": [
    {
      "point": "Proposes lightweight, embedding-based OOD detection methods that outperform perplexity and other baselines.",
      "evidence": "RMD and binary classifier OOD scores achieve AUROC above 0.8 on summarization and translation, outperforming perplexity, NLI score, COMET, and Prism."
    },
    {
      "point": "Demonstrates that combining OOD scores with perplexity improves selective generation quality prediction.",
      "evidence": "Combined scores improve correlation with human and BLEURT quality metrics by up to 12% absolute for summarization and 8% for translation, outperforming single metrics and external models."
    },
    {
      "point": "Introduces a selective generation framework with evaluation metrics including Quality vs Abstention curves.",
      "evidence": "QA curves show combined scores enable effective abstention on low-quality OOD outputs while retaining high-quality in-domain outputs."
    }
  ],
  "weaknesses": [
    {
      "point": "Lacks comparison to recent state-of-the-art OOD detection methods for language models.",
      "evidence": "No baselines such as energy-based models or density estimation approaches on hidden states are included."
    },
    {
      "point": "Insufficient methodological justification and ablations for key design choices.",
      "evidence": "No justification for Gaussian assumption on embeddings, no ablation on embedding aggregation strategies, and no analysis of combination methods for OOD and perplexity scores."
    },
    {
      "point": "Limited evaluation scope and missing details affecting reproducibility.",
      "evidence": "Experiments restricted to summarization and translation; background dataset construction and logistic regression hyperparameters are not detailed."
    },
    {
      "point": "Evaluation metrics and interpretability analyses are limited or underexplored.",
      "evidence": "Only AUROC reported for OOD detection without metrics like FPR at 95% TPR; selective generation evaluated only via correlation without absolute quality or calibration metrics; visualization methods for interpretability are not described."
    },
    {
      "point": "No discussion of computational overhead or applicability to other CLM architectures.",
      "evidence": "Computational cost of embedding extraction and Mahalanobis computations at inference is not quantified; approach applicability to decoder-only or non-autoregressive models is not addressed."
    }
  ],
  "questions": [
    {
      "question": "How does the proposed method compare to recent advanced OOD detection techniques tailored for language models?",
      "motivation": "Understanding relative performance against state-of-the-art is critical to assess novelty and practical impact."
    },
    {
      "question": "Is the Gaussian assumption on embeddings valid, and would alternative density estimators improve OOD detection?",
      "motivation": "Mahalanobis distance relies on Gaussianity; if this assumption is weak, detection quality may degrade."
    },
    {
      "question": "How sensitive are the results to the choice and construction of the background dataset used for fitting the general-domain Gaussian?",
      "motivation": "Reproducibility and robustness depend on background data characteristics."
    },
    {
      "question": "Can the approach generalize effectively to other conditional generation tasks and CLM architectures beyond summarization and translation?",
      "motivation": "Claims of broad applicability require empirical validation to ensure practical utility."
    }
  ],
  "scores": {
    "correctness": 3,
    "novelty": 3,
    "recommendation": "borderline",
    "confidence": 3
  }
}
